function encodeVoidValue(_value: undefined): CborValue {
  return null;
}

function decodeVoidValue(_value: CborValue): undefined {
  return undefined;
}

function expectMap(value: CborValue): Map<number, CborValue> {
  if (!(value instanceof Map)) throw new Error("expected CBOR map");
  return value;
}

function expectUnion(value: CborValue): [number, Map<number, CborValue>] {
  if (!Array.isArray(value) || value.length !== 2) {
    throw new Error("expected CBOR union tuple");
  }
  return [integer(value[0]), expectMap(value[1])];
}

function array(value: CborValue): CborValue[] {
  if (!Array.isArray(value)) throw new Error("expected CBOR array");
  return value;
}

function integer(value: CborValue): number {
  if (typeof value !== "number" || !Number.isSafeInteger(value)) {
    throw new Error("expected CBOR integer");
  }
  return value;
}

function textValue(value: CborValue): string {
  if (typeof value !== "string") throw new Error("expected CBOR text");
  return value;
}

function boolValue(value: CborValue): boolean {
  if (typeof value !== "boolean") throw new Error("expected CBOR bool");
  return value;
}

function bytesValue(value: CborValue): Uint8Array {
  if (!(value instanceof Uint8Array)) throw new Error("expected CBOR bytes");
  return value;
}

function optionalField<T>(
  value: CborValue | undefined,
  decode: (value: CborValue) => T,
): T | undefined {
  return value === undefined ? undefined : decode(value);
}

function fieldOrDefault<T>(
  value: CborValue | undefined,
  decode: (value: CborValue) => T,
  fallback: () => T,
): T {
  return value === undefined ? fallback() : decode(value);
}

function required<T>(value: T | undefined, label: string): T {
  if (value === undefined) throw new Error(`missing required field ${label}`);
  return value;
}

function u53(value: number): CborValue {
  if (!Number.isSafeInteger(value) || value < 0) {
    throw new Error("expected u53");
  }
  return value;
}

function i53(value: number): CborValue {
  if (!Number.isSafeInteger(value)) throw new Error("expected i53");
  return value;
}

function text(value: string): CborValue {
  if (typeof value !== "string") throw new Error("expected string");
  return value;
}

function bool(value: boolean): CborValue {
  if (typeof value !== "boolean") throw new Error("expected boolean");
  return value;
}

function bytes(value: Uint8Array): CborValue {
  if (!(value instanceof Uint8Array)) throw new Error("expected Uint8Array");
  return value;
}
